// 使用方式 v-default={value:默认值,prop:属性} 表单组件上写name
export default {
	install(Vue) {
		Vue.directive('default', {
			inserted(el, bind, vnode) {
				const { value, prop } = bind.value;

				const targetName = prop || vnode.componentInstance.name;
				// 原来有值的话就不动
				const originValue = vnode.context.$data[targetName];
				console.log('origin', originValue);
				if (!originValue || (Array.isArray(originValue) && originValue.length < 1)) {
					vnode.context.$data[targetName] = value;
				}
			},
		});
	},
};
